INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('8364ef45acb1e708', 'WI', '["federal"]', 'candidate_eligibility', 'Is there a U.S. Senate election in Wisconsin in 2026?', '["Are Tammy Baldwin or Ron Johnson up for re-election in 2026?","When is the next Wisconsin US Senate race?","2026 Wisconsin Senate candidates"]', 'No. There is no U.S. Senate race in Wisconsin for the 2026 cycle. Senator Tammy Baldwin won re-election in November 2024 and is next up in 2030, while Senator Ron Johnson is next up for re-election in 2028.', 'https://elections.wi.gov/elections', 'Wisconsin Elections Commission – Election Schedule', '2026-05-12', 'per_cycle', 'official_source_direct', 'Federal candidates and consultants', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('5bb9418613e3de5c', 'WI', '["state"]', 'candidate_eligibility', 'Is Governor Tony Evers running for re-election in 2026?', '["Is the Wisconsin Governor''s seat open in 2026?","Can Evers seek a third term?","Wisconsin 2026 gubernatorial candidates"]', 'No. Governor Tony Evers announced in July 2025 that he will not seek a third term, leaving the Wisconsin gubernatorial seat open for the 2026 cycle.', 'https://elections.wi.gov/candidates', 'Wisconsin Elections Commission – Candidate Information', '2026-05-12', 'volatile', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('fbb9b67feba633f7', 'WI', '["judicial"]', 'election_dates', 'What was the outcome of the 2026 Wisconsin Supreme Court spring election?', '["Who won the April 7 Wisconsin Supreme Court race?","Wisconsin Supreme Court liberal majority 2026","Rebecca Bradley retirement Wisconsin"]', 'In the April 7, 2026 spring election, liberal-backed Chris Taylor defeated conservative-backed Maria Lazar by approximately 20 percentage points to fill the seat being vacated by retiring conservative Justice Rebecca Bradley, expanding the court''s liberal majority from 4-3 to 5-2. Bradley announced in late 2025 she would not seek reelection. Taylor will be sworn in August 1, 2026.', 'https://elections.wi.gov/elections/election-results', 'Wisconsin Elections Commission – Election Results', '2026-05-12', 'static', 'official_source_direct', 'Judicial candidates and Campaigns', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('f9b66c6958572d94', 'WI', '["federal","state","county"]', 'election_dates', 'When is the 2026 partisan primary election in Wisconsin?', '["What date is the WI primary in 2026?","Wisconsin August primary date","When do polls open for the WI partisan primary?"]', 'The Wisconsin partisan primary election is scheduled for Tuesday, August 11, 2026.', 'https://docs.legis.wisconsin.gov/statutes/statutes/5/02/12s', 'Wis. Stat. § 5.02(12s)', '2026-05-12', 'per_cycle', 'statute_citation', 'All candidates and voters', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('d5852a28a1945b6e', 'WI', '["federal","state","county","municipal"]', 'election_dates', 'When is the 2026 general election in Wisconsin?', '["What date is the WI general election in 2026?","Wisconsin 2026 midterm election date","When is Election Day 2026 in Wisconsin?"]', 'The general election in Wisconsin will be held on Tuesday, November 3, 2026.', 'https://docs.legis.wisconsin.gov/statutes/statutes/5/02/5', 'Wis. Stat. § 5.02(5)', '2026-05-12', 'per_cycle', 'statute_citation', 'All candidates and voters', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('af4b7db40b52087a', 'WI', '["judicial","municipal","special_district"]', 'election_dates', 'When was the 2026 spring election held in Wisconsin?', '["Wisconsin April election date 2026","When did we vote for Supreme Court in WI?","Spring election calendar Wisconsin"]', 'The Wisconsin spring election, which includes nonpartisan races for judicial, municipal, and school board offices, was held on Tuesday, April 7, 2026.', 'https://docs.legis.wisconsin.gov/statutes/statutes/5/02/21', 'Wis. Stat. § 5.02(21)', '2026-05-12', 'per_cycle', 'statute_citation', 'Local and Judicial candidates', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('6d927eec2967d09a', 'WI', '["judicial","municipal","special_district"]', 'election_dates', 'When was the 2026 spring primary held in Wisconsin?', '["Wisconsin February primary date","When was the nonpartisan primary in WI?","Spring primary election calendar"]', 'The Wisconsin spring primary for nonpartisan offices was held on Tuesday, February 17, 2026.', 'https://docs.legis.wisconsin.gov/statutes/statutes/5/02/22', 'Wis. Stat. § 5.02(22)', '2026-05-12', 'per_cycle', 'statute_citation', 'Local and Judicial candidates', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('7cdc36e962dd1fc4', 'WI', '["federal","state","county","municipal","judicial"]', 'finance_ethics', 'What is the jurisdictional split between the Wisconsin Elections Commission and the Wisconsin Ethics Commission?', '["Who enforces campaign finance vs election law in WI?","Does the Secretary of State run elections in Wisconsin?","WEC vs Ethics Commission roles"]', 'The Wisconsin Elections Commission (WEC) administers elections and ballot access, while the separate Wisconsin Ethics Commission handles campaign finance reporting, contribution limits, and lobbying regulations. Distinctively, the Wisconsin Secretary of State does not administer elections.', 'https://ethics.wi.gov/Pages/AboutUs/AboutUs.aspx', 'Wisconsin Ethics Commission – About Us', '2026-05-12', 'static', 'official_source_direct', 'Candidates, Consultants, and Legal Counsel', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('5caca384aeda2274', 'WI', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Is a photo ID required to vote at the polls in Wisconsin?', '["Wisconsin voter ID laws","Do I need my driver''s license to vote in WI?","Poll ID requirements Wisconsin"]', 'Yes. Wisconsin law strictly requires voters to show an acceptable photo ID to vote at their polling place. Acceptable IDs include a Wisconsin driver''s license, state ID card, U.S. passport, or military ID.', 'https://docs.legis.wisconsin.gov/statutes/statutes/5/02/6m', 'Wis. Stat. § 5.02(6m)', '2026-05-12', 'static', 'statute_citation', 'All voters', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('c25033fff892fb7e', 'WI', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Does Wisconsin allow same-day voter registration at polling places?', '["Can I register to vote at the polls in Wisconsin?","Same-day registration rules WI","Is there an Election Day Registration option?"]', 'Yes. Eligible voters in Wisconsin can register to vote at their polling place on Election Day by providing an acceptable proof of residence document.', 'https://docs.legis.wisconsin.gov/statutes/statutes/6/iii/55/2', 'Wis. Stat. § 6.55(2)', '2026-05-12', 'static', 'statute_citation', 'Unregistered voters', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('45743e2e8d334cfa', 'WI', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Are secure drop boxes for absentee ballots legally permitted in Wisconsin for 2026?', '["Did the Supreme Court bring back drop boxes in WI?","Can I put my absentee ballot in a drop box?","Priorities USA v. WEC drop box ruling"]', 'Yes. In its July 2024 ruling in Priorities USA v. WEC, the Wisconsin Supreme Court restored the authority of municipal clerks to use secure, unstaffed drop boxes for the return of absentee ballots, overturning a previous 2022 ban. The Wisconsin Elections Commission provides operational guidance to municipal clerks on drop box security.', 'https://elections.wi.gov/voters/absentee-voting', 'Wisconsin Elections Commission – Absentee Voting', '2026-05-12', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('13aeb66dd6db504e', 'WI', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Does an absentee ballot require a witness signature in Wisconsin?', '["Who can witness an absentee ballot in WI?","Does someone have to watch me vote by mail?","Wisconsin absentee ballot witness requirement"]', 'Yes. Wisconsin law requires that a voter mark their absentee ballot in the presence of an adult U.S. citizen witness. The witness must sign the certificate envelope for the ballot to be counted.', 'https://docs.legis.wisconsin.gov/statutes/statutes/6/iv/87/4/b/1', 'Wis. Stat. § 6.87(4)(b)1', '2026-05-12', 'static', 'statute_citation', 'Absentee voters', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('6a5f2021a8c29f61', 'WI', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'What address information must a witness provide on a Wisconsin absentee ballot envelope?', '["Absentee witness address rules WI","Will my ballot be rejected if the witness leaves off their address?","Curing a witness address error"]', 'A witness must sign the absentee ballot certificate envelope and provide their printed name and complete address. Following multiple court decisions, if the address is missing, the ballot may be rejected. WEC guidance limits the ability of municipal clerks to cure (add missing information to) witness certificates without the voter.', 'https://docs.legis.wisconsin.gov/statutes/statutes/6/iv/87/2', 'Wis. Stat. § 6.87(2)', '2026-05-12', 'static', 'statute_citation', 'Absentee voters and Poll Watchers', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('c8f19a77ce015ef6', 'WI', '["federal","state","county","municipal","judicial"]', 'candidate_eligibility', 'Can a person with a felony conviction vote in Wisconsin?', '["Felon voting rights WI","Can I vote after getting off probation in Wisconsin?","Voting post-incarceration rules WI"]', 'Yes, but only after they have fully completed their sentence, which includes serving any term of incarceration as well as any period of probation, parole, or extended supervision. Voting rights are then automatically restored, but the individual must re-register to vote.', 'https://docs.legis.wisconsin.gov/statutes/statutes/6/i/03/1/b', 'Wis. Stat. § 6.03(1)(b)', '2026-05-12', 'static', 'statute_citation', 'All eligible citizens', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('d73a60de0779d4b7', 'WI', '["federal","state","county"]', 'voter_interaction', 'Does Wisconsin have an open primary system?', '["Can an independent vote in the Wisconsin Democratic primary?","Do I have to register with a party to vote in the primary?","Open primary rules WI"]', 'Yes. Wisconsin holds open primaries, meaning voters do not need to be registered with a specific political party to participate. However, on the partisan primary ballot, a voter can only vote for candidates within one chosen party.', 'https://docs.legis.wisconsin.gov/statutes/statutes/5/02/12', 'Wis. Stat. § 5.02(12)', '2026-05-12', 'static', 'statute_citation', 'Voters and Campaigns', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('36b7db820bc41831', 'WI', '["federal","state","county"]', 'filing_requirements', 'What is the candidate filing deadline for the August 11, 2026 Wisconsin partisan primary?', '["When did candidates have to file for the 2026 primary in Wisconsin?","Declaration of candidacy deadline 2026","Wisconsin June 1 filing deadline"]', 'The deadline for candidates to file nomination papers and declarations of candidacy for the August 11, 2026 partisan primary was June 1, 2026, at 5:00 p.m.', 'https://docs.legis.wisconsin.gov/statutes/statutes/8/15/1', 'Wis. Stat. § 8.15(1)', '2026-05-12', 'per_cycle', 'statute_citation', 'Major party candidates', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('8c61c9e7e7ac97de', 'WI', '["state","federal"]', 'ballot_access', 'How many nomination signatures are required to run for Governor or U.S. Senate in Wisconsin?', '["Signature requirement for WI Governor","How many signatures to run statewide in WI?","Statewide petition thresholds Wisconsin"]', 'Candidates seeking major party nomination for statewide offices like Governor or U.S. Senate must collect a minimum of 2,000 and a maximum of 4,000 valid signatures from eligible voters.', 'https://docs.legis.wisconsin.gov/statutes/statutes/8/15/6/a', 'Wis. Stat. § 8.15(6)(a)', '2026-05-12', 'static', 'statute_citation', 'Statewide and U.S. Senate candidates', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('19b12b3a4d9898d5', 'WI', '["federal"]', 'ballot_access', 'How many nomination signatures are required to run for U.S. House in Wisconsin?', '["Signature threshold for Congress WI","How many signatures to run for US House in Wisconsin?","Congressional district petition requirements"]', 'Candidates seeking major party nomination for a U.S. House of Representatives seat must collect a minimum of 1,000 and a maximum of 2,000 valid signatures from eligible voters within the congressional district.', 'https://docs.legis.wisconsin.gov/statutes/statutes/8/15/6/b', 'Wis. Stat. § 8.15(6)(b)', '2026-05-12', 'static', 'statute_citation', 'U.S. House candidates', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('d5e3ca7ed1d83352', 'WI', '["state"]', 'ballot_access', 'What are the signature requirements for State Senate and State Assembly nomination papers in Wisconsin?', '["Signatures needed for WI State Legislature","How many signatures to run for State Assembly WI?","State Senate petition thresholds"]', 'Major party candidates for State Senate must collect between 400 and 800 valid signatures. Candidates for State Assembly must collect between 200 and 400 valid signatures from eligible voters within their respective districts.', 'https://docs.legis.wisconsin.gov/statutes/statutes/8/15/6/c', 'Wis. Stat. § 8.15(6)(c)', '2026-05-12', 'static', 'statute_citation', 'State Legislative candidates', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('c287a5e22a89109a', 'WI', '["state"]', 'candidate_eligibility', 'Are there term limits for the Governor or state legislators in Wisconsin?', '["How long can someone serve as Governor in WI?","State Representative term limits Wisconsin","State Senate consecutive terms"]', 'No. While the Wisconsin Constitution Article XIII Section 12 governs recalls, there is no constitutional or statutory provision imposing term limits on the Governor, other statewide executive officers, or members of the State Legislature.', 'https://docs.legis.wisconsin.gov/constitution/wi', 'Wisconsin Constitution', '2026-05-12', 'static', 'statute_citation', 'Statewide and Legislative candidates', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('acd49d9ff73bfa2e', 'WI', '["state"]', 'candidate_eligibility', 'What are the age and residency requirements to run for Governor in Wisconsin?', '["How old do you have to be to be WI Governor?","Gubernatorial candidate residency rules","Do I have to live in Wisconsin for 5 years to run for Governor?"]', 'To be eligible to run for Governor or Lieutenant Governor, a candidate must simply be a citizen of the United States and a qualified elector of the state (which requires being at least 18 years old and a resident for at least 28 consecutive days). Distinctively, there is no 30-year age or 5-year durational residency requirement in Wisconsin.', 'https://docs.legis.wisconsin.gov/constitution/wi/000230/000002', 'Wisconsin Constitution Article V § 2', '2026-05-12', 'static', 'statute_citation', 'Gubernatorial candidates', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('db60910694328061', 'WI', '["state","county","municipal","judicial"]', 'recall_rules', 'Can voters recall a statewide official or state legislator in Wisconsin?', '["Statewide recall mechanism WI","How to recall the Governor in Wisconsin","Recall signature threshold Wisconsin"]', 'Yes. Voters can recall any incumbent elective officer after their first year of their term. Proponents have a 60-day window to gather signatures equal to at least 25% of the vote cast for the office of governor at the last preceding election within the district or state.', 'https://docs.legis.wisconsin.gov/constitution/wi/000238/000012', 'Wisconsin Constitution Article XIII § 12', '2026-05-12', 'static', 'statute_citation', 'Voters and Campaigns', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('3c0dcc93a7ba989e', 'WI', '["state"]', 'finance_ethics', 'What are the 2025-2026 individual contribution limits for Wisconsin state campaigns?', '["How much can an individual give to a Governor candidate in WI?","Statewide contribution limits Wisconsin","State Assembly maximum donation"]', 'Under Wis. Stat. § 11.1101, individuals may contribute up to $20,000 per campaign to candidates for ANY statewide office (Governor, Lt. Governor, AG, Secretary of State, Treasurer, Superintendent, Supreme Court). Limits for State Senate are $2,000, and State Assembly are $1,000.', 'https://docs.legis.wisconsin.gov/statutes/statutes/11/ci/1101', 'Wis. Stat. § 11.1101(1)', '2026-05-12', 'static', 'statute_citation', 'All state candidates and donors', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('b27b1cc3ca931fbb', 'WI', '["state"]', 'finance_ethics', 'What are the PAC contribution limits for Wisconsin state campaigns?', '["How much can a PAC give to a candidate in WI?","PAC contribution limits Wisconsin","Super PAC direct donation rules"]', 'Political Action Committees (PACs) have different limits than individuals. A PAC may contribute up to $86,000 to a gubernatorial candidate, $44,000 for Attorney General, $26,000 for Lt. Governor, and $18,000 for other statewide offices. Legislative limits remain $2,000 for Senate and $1,000 for Assembly.', 'https://docs.legis.wisconsin.gov/statutes/statutes/11/ci/1101', 'Wis. Stat. § 11.1101(3)', '2026-05-12', 'static', 'statute_citation', 'PACs and Campaign Treasurers', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('1e05ccb5d7860f47', 'WI', '["state","county","municipal","judicial"]', 'finance_ethics', 'Are Wisconsin contribution limits applied per election or per election cycle?', '["Primary and general contribution limits WI","Wisconsin campaign cycle definition","Can I donate the max limit twice in one year?"]', 'Distinctively, under Wisconsin''s 2015 Act 117 reforms, contribution limits apply to the entire campaign cycle, not per election. A candidate cannot receive the maximum limit for the primary and then again for the general; the single limit covers the entire period. The cycle is 4 years for statewide offices and State Senate, 2 years for State Assembly, and 10 years for Supreme Court Justices.', 'https://docs.legis.wisconsin.gov/statutes/statutes/11/ci/1101', 'Wis. Stat. § 11.1101', '2026-05-12', 'static', 'statute_citation', 'Campaign Treasurers and Donors', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('bc4980c4958375a1', 'WI', '["state","county","municipal","judicial"]', 'finance_ethics', 'When does a campaign contribution cycle begin in Wisconsin?', '["When do donation limits reset in WI?","Act 117 cycle trigger","Does the campaign cycle start on Election Day?"]', 'For an incumbent, the campaign cycle begins on the day after the general election for that office. For a non-incumbent challenger, the cycle begins on the date they first register their campaign committee or become a candidate under the law.', 'https://docs.legis.wisconsin.gov/statutes/statutes/11/ci/1101', 'Wis. Stat. § 11.1101', '2026-05-12', 'static', 'statute_citation', 'Campaign Treasurers and Donors', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('2c6c6c2c7aaaf2cc', 'WI', '["state","county","municipal","judicial"]', 'finance_ethics', 'Can a corporation or union contribute directly to a candidate for state office in Wisconsin?', '["Are corporate contributions legal in WI?","Can my business donate to a state candidate?","Labor union donation rules Wisconsin"]', 'No. Wisconsin law strictly prohibits corporations, labor organizations, and federally recognized Indian tribes from making direct contributions to candidates or political parties. They may, however, establish and administer separate segregated PACs to make contributions.', 'https://docs.legis.wisconsin.gov/statutes/statutes/11/ci/1112', 'Wis. Stat. § 11.1112', '2026-05-12', 'static', 'statute_citation', 'Corporations, Unions, and Campaign Treasurers', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('1a9b7962b97d3d0f', 'WI', '["state","county","municipal","judicial"]', 'finance_ethics', 'What is the 72-hour reporting rule for late contributions in Wisconsin?', '["When do I have to report late donations in WI?","15-day pre-election contribution reporting","Wisconsin late contribution threshold"]', 'Under Wis. Stat. § 11.0204(7), campaigns must report any contribution or cumulative contributions of $1,000 or more from a single contributor received within 15 days before an election. This report applies only to contributions, not expenditures, and must be filed with the Ethics Commission within 72 hours of receipt.', 'https://docs.legis.wisconsin.gov/statutes/statutes/11/cii/0204', 'Wis. Stat. § 11.0204(7)', '2026-05-12', 'static', 'statute_citation', 'Campaign Treasurers', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('036a2f15b825d63e', 'WI', '["state","county","municipal","judicial"]', 'finance_ethics', 'What are the registration and bank account requirements to run for office in Wisconsin?', '["Campaign treasurer designation WI","Can I use my personal checking account for donations?","Wisconsin campaign depository requirements"]', 'Before receiving or spending any funds, a candidate must file a campaign registration statement designating a campaign treasurer. The campaign must also establish a separate depository bank account; commingling campaign funds with personal or business funds is strictly prohibited.', 'https://docs.legis.wisconsin.gov/statutes/statutes/11/cii/0201', 'Wis. Stat. § 11.0201', '2026-05-12', 'static', 'statute_citation', 'Campaign Treasurers and Candidates', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('423c657867621d27', 'WI', '["state","county","municipal","judicial"]', 'finance_ethics', 'What are the contribution limits from political parties to candidates in Wisconsin?', '["How much can the state party give to my campaign?","Political party unlimited contributions WI","Legislative campaign committee limits"]', 'Under Wisconsin law, political party committees and legislative campaign committees are permitted to make unlimited contributions to their candidates. They are not subject to the monetary caps placed on individuals or PACs.', 'https://docs.legis.wisconsin.gov/statutes/statutes/11/ci/1104', 'Wis. Stat. § 11.1104', '2026-05-12', 'static', 'statute_citation', 'Political Parties and Candidates', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('06179d87ac94ff82', 'WI', '["state","county","municipal","judicial"]', 'finance_ethics', 'Who enforces campaign finance rules in Wisconsin?', '["Wisconsin Ethics Commission jurisdiction","Who do I file my campaign finance reports with?","Does the WEC handle campaign finance?"]', 'Campaign finance, lobbying regulations, and ethics laws are enforced by the Wisconsin Ethics Commission, a six-member bipartisan body. It operates entirely separately from the Wisconsin Elections Commission, which handles ballot access and election administration.', 'https://ethics.wi.gov/Pages/AboutUs/AboutUs.aspx', 'Wisconsin Ethics Commission – About Us', '2026-05-12', 'static', 'official_source_direct', 'Candidates, Consultants, and Legal Counsel', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('15fd18a034230bfd', 'WI', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'What is the Wisconsin Elections Commission (WEC)?', '["Who administers elections in Wisconsin?","WEC composition and structure","Does the Secretary of State run WI elections?"]', 'The WEC is the state agency responsible for administering elections, managing the voter registration database, and providing guidance to the state''s 1,922 municipal clerks. Created in 2015 to replace the Government Accountability Board, it is a six-member bipartisan commission with equal Republican and Democratic representation.', 'https://elections.wi.gov/', 'Wisconsin Elections Commission', '2026-05-12', 'static', 'official_source_direct', 'Voters, Campaigns, and Legal Counsel', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('cba9052b28f166be', 'WI', '["federal","state","county","municipal","judicial"]', 'election_dates', 'What is the status of Wisconsin Elections Commission Administrator Meagan Wolfe?', '["Is Meagan Wolfe still the WEC administrator?","Wisconsin Elections Commission leadership 2026","WEC administrator confirmation ruling"]', 'In a February 2025 ruling, the Wisconsin Supreme Court unanimously determined that Meagan Wolfe can legally continue to serve as the WEC Administrator as a holdover appointee, resolving a prolonged partisan dispute over her confirmation and removal by the State Senate.', 'https://elections.wi.gov/', 'Wisconsin Elections Commission', '2026-05-12', 'static', 'official_source_direct', 'Campaign Strategists and Consultants', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('f8338c0fa39a6670', 'WI', '["state","county","municipal","judicial"]', 'finance_ethics', 'Do campaign contribution limits apply during a recall election in Wisconsin?', '["Recall financing limits Wisconsin","Can a recalled politician raise unlimited money?","Act 117 recall contribution caps"]', 'Under 2015 Wisconsin Act 117, regular contribution limits are temporarily lifted for incumbent officeholders during the signature collection period of a recall effort against them. The incumbent can accept unlimited contributions to defend against the recall until the petition is officially filed or the window closes.', 'https://docs.legis.wisconsin.gov/statutes/statutes/11/ci/1103', 'Wis. Stat. § 11.1103', '2026-05-12', 'static', 'statute_citation', 'Incumbent officials facing recall', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('fd0aa783971efa7e', 'WI', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'What forms of photo ID are acceptable to vote in Wisconsin?', '["Wisconsin voter ID list","Can I use my student ID to vote in WI?","Acceptable poll ID requirements"]', 'Acceptable IDs under Wis. Stat. § 5.02(6m) include a Wisconsin driver''s license or state ID, U.S. passport, military ID, certificate of naturalization, tribal ID, or a specific student ID card (provided it includes an issuance date, expiration date, and signature, and is accompanied by proof of current enrollment).', 'https://docs.legis.wisconsin.gov/statutes/statutes/5/02/6m', 'Wis. Stat. § 5.02(6m)', '2026-05-12', 'static', 'statute_citation', 'All voters', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('6201ced009c3678a', 'WI', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Who qualifies as an indefinitely confined voter in Wisconsin?', '["Indefinitely confined absentee ballot rules","Do indefinitely confined voters need a photo ID?","Trump v. Biden 2020 Wisconsin ruling"]', 'Under Wis. Stat. § 6.86(2), a voter who is indefinitely confined due to age, physical illness, infirmity, or disability may receive absentee ballots automatically without a photo ID, using their witness''s signature for verification. The Wisconsin Supreme Court ruled in 2020 that pandemic concerns did not grant blanket exemption; the status requires an individual assessment.', 'https://docs.legis.wisconsin.gov/statutes/statutes/6/iv/86/2', 'Wis. Stat. § 6.86(2)', '2026-05-12', 'static', 'statute_citation', 'Voters and Get-Out-The-Vote Operations', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('49f3cf86336dee29', 'WI', '["federal","state","county","municipal","judicial"]', 'filing_requirements', 'What is the candidate filing fee in Wisconsin?', '["How much does it cost to run for office in WI?","Wisconsin filing fee amount","Do I have to pay to get on the ballot?"]', 'Wisconsin does not require candidates to pay a filing fee to run for office. Ballot access is achieved exclusively by circulating and submitting the statutorily required number of valid nomination petition signatures.', 'https://elections.wi.gov/candidates/ballot-access', 'Wisconsin Elections Commission – Ballot Access', '2026-05-12', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('38c912191c89523f', 'WI', '["federal","state","county"]', 'filing_requirements', 'What is the nomination paper circulation window for the August 2026 partisan primary?', '["When can I start collecting signatures in WI?","April 15 to June 1 signature window","Nomination paper deadlines Wisconsin"]', 'Candidates may begin circulating nomination papers on April 15, 2026. The completed petitions and declaration of candidacy must be filed with the Wisconsin Elections Commission no later than 5:00 p.m. on June 1, 2026.', 'https://docs.legis.wisconsin.gov/statutes/statutes/8/15/1', 'Wis. Stat. § 8.15(1)', '2026-05-12', 'per_cycle', 'statute_citation', 'Major party candidates', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('a9441ac270f9aade', 'WI', '["state"]', 'candidate_eligibility', 'Which Wisconsin statewide executive offices are up for election in 2026?', '["Who is on the ballot in Wisconsin in 2026?","Is the Attorney General up for reelection?","2026 Wisconsin state elections"]', 'The 2026 ballot features elections for Governor (open seat), Lieutenant Governor (Sara Rodriguez, D), Attorney General (Josh Kaul, D), Secretary of State (Sarah Godlewski, D), and State Treasurer (John Leiber, R).', 'https://elections.wi.gov/elections', 'Wisconsin Elections Commission', '2026-05-12', 'per_cycle', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('ad742527edb956c3', 'WI', '["state"]', 'redistricting', 'Why were Wisconsin''s state legislative maps redrawn for 2024 and 2026?', '["Did Wisconsin redraw its assembly districts for 2026?","Clarke v. WEC redistricting maps","Are we using new maps for the state legislature?"]', 'In December 2023, the Wisconsin Supreme Court ruled in Clarke v. WEC that the existing legislative maps violated the state constitution''s ''contiguous territory'' requirement. Governor Tony Evers signed new, constitutionally compliant maps in February 2024, which remain stable and active for the 2026 cycle.', 'https://docs.legis.wisconsin.gov/statutes/statutes/4', 'Wis. Stat. Chapter 4 (Apportionment)', '2026-05-12', 'static', 'statute_citation', 'State Legislative candidates', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('55405f124f5e4d44', 'WI', '["federal"]', 'redistricting', 'Are Wisconsin''s congressional maps subject to the same state-level redistricting lawsuits as the legislative maps?', '["Did the Wisconsin Supreme Court strike down congressional maps?","Congressional redistricting status WI","Rucho v Common Cause effect in Wisconsin"]', 'As of the 2026 cycle, the congressional maps drawn earlier in the decade remain in effect. While the U.S. Supreme Court''s Rucho v. Common Cause decision precluded federal courts from hearing partisan gerrymandering claims, the state-level Clarke v. WEC ruling specifically applied only to the state legislative maps.', 'https://docs.legis.wisconsin.gov/statutes/statutes/3', 'Wis. Stat. Chapter 3 (Congressional Districts)', '2026-05-12', 'static', 'statute_citation', 'U.S. House candidates', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('ea33babd9aee5a58', 'WI', '["judicial"]', 'election_dates', 'How are judges selected for the Wisconsin Court of Appeals?', '["Are appellate judges partisan in Wisconsin?","Court of Appeals selection process","Court of appeals term length WI"]', 'The 16 judges of the Wisconsin Court of Appeals are elected in nonpartisan spring elections to serve six-year terms. Mid-term vacancies are filled by gubernatorial appointment, and the appointee must stand for election at the next spring election.', 'https://docs.legis.wisconsin.gov/constitution/wi/000232/000005', 'Wisconsin Constitution Article VII § 5', '2026-05-12', 'static', 'statute_citation', 'Judicial candidates', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('87c8aeca32efd87d', 'WI', '["judicial"]', 'election_dates', 'How are Wisconsin Circuit Court judges elected?', '["Circuit Court selection mechanism","Are trial judges nonpartisan in Wisconsin?","Circuit court term lengths WI"]', 'Circuit Court judges in Wisconsin are elected in nonpartisan spring elections to six-year terms. Similar to the appellate courts, vacancies are filled by the Governor until the next available spring election.', 'https://docs.legis.wisconsin.gov/constitution/wi/000232/000007', 'Wisconsin Constitution Article VII § 7', '2026-05-12', 'static', 'statute_citation', 'Judicial candidates', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('1a208916996912bd', 'WI', '["federal","state","county","municipal","judicial"]', 'filing_requirements', 'What is the deadline to register as a write-in candidate in Wisconsin?', '["When must write-in candidates file in WI?","Write-in registration deadline","How late can I declare a write-in campaign?"]', 'To have their votes officially counted, a write-in candidate must file a registration statement and declaration of candidacy by 12:00 noon on the Friday immediately preceding the election.', 'https://docs.legis.wisconsin.gov/statutes/statutes/7/ii/50/2/em', 'Wis. Stat. § 7.50(2)(em)', '2026-05-12', 'static', 'statute_citation', 'Write-in candidates', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('e370377f0e64d3f5', 'WI', '["federal"]', 'candidate_eligibility', 'What are the age and residency requirements to run for U.S. House in Wisconsin?', '["Do I have to live in the district to run for Congress in WI?","Congressional age limit Wisconsin","US House qualifications"]', 'Under the U.S. Constitution, a candidate for the U.S. House of Representatives must be at least 25 years old, a U.S. citizen for seven years, and an inhabitant of Wisconsin when elected. District residency is not required.', 'https://elections.wi.gov/candidates/ballot-access', 'Wisconsin Elections Commission – Ballot Access', '2026-05-12', 'static', 'official_source_direct', 'U.S. House candidates', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('8dbc647a6330dee9', 'WI', '["state"]', 'candidate_eligibility', 'What are the age and residency requirements to run for the Wisconsin State Legislature?', '["How old to run for State Assembly WI?","State Senate residency requirements","Do I have to live in the district to run for the legislature?"]', 'To run for the State Senate or State Assembly, a candidate must be a resident of Wisconsin for one year and a qualified elector (at least 18 years old) of the specific district they seek to represent.', 'https://docs.legis.wisconsin.gov/constitution/wi/000229/000006', 'Wisconsin Constitution Article IV § 6', '2026-05-12', 'static', 'statute_citation', 'State Legislative candidates', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('1cde9acc3d97821c', 'WI', '["judicial"]', 'candidate_eligibility', 'What are the qualifications to run for the Wisconsin Supreme Court?', '["Do Supreme Court justices have to be lawyers in WI?","Wisconsin judicial qualifications","How long must I practice law to be a judge?"]', 'A candidate for the Wisconsin Supreme Court, Court of Appeals, or Circuit Court must be a qualified elector of the state and must have been licensed to practice law in Wisconsin for at least five years immediately prior to their election or appointment.', 'https://docs.legis.wisconsin.gov/constitution/wi/000232/000024', 'Wisconsin Constitution Article VII § 24', '2026-05-12', 'static', 'statute_citation', 'Judicial candidates', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('4e51f9c765db9f78', 'WI', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'When does early voting (in-person absentee voting) begin in Wisconsin?', '["When can I vote early in WI?","In-person absentee voting window","Wisconsin early voting hours"]', 'In-person absentee voting, often referred to as early voting, begins 14 days before the election. The period ends on the Sunday immediately preceding Election Day, with specific office hours set by individual municipal clerks.', 'https://docs.legis.wisconsin.gov/statutes/statutes/6/iv/86/1/b', 'Wis. Stat. § 6.86(1)(b)', '2026-05-12', 'static', 'statute_citation', 'Voters and Campaigns', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('e01f3097154cbb1f', 'WI', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'What documents are accepted as proof of residence for same-day voter registration in Wisconsin?', '["How do I prove my address to vote in WI?","Same-day registration documents Wisconsin","Election day registration proof"]', 'Voters registering on Election Day must provide proof of residence. Acceptable documents include a utility bill, bank statement, paycheck, or government document issued within the last 90 days that displays the voter''s current name and address.', 'https://docs.legis.wisconsin.gov/statutes/statutes/6/iii/34/3/a', 'Wis. Stat. § 6.34(3)(a)', '2026-05-12', 'static', 'statute_citation', 'Unregistered voters', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('1555220e809dba4d', 'WI', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'How long must I live in Wisconsin before I can vote?', '["Wisconsin voter residency requirement","28-day residency rule WI","When do I have to move to Wisconsin to vote?"]', 'Wisconsin law requires voters to have resided in their current ward or election district for at least 28 consecutive days before the election to be eligible to vote there.', 'https://docs.legis.wisconsin.gov/statutes/statutes/6/i/02/1', 'Wis. Stat. § 6.02(1)', '2026-05-12', 'static', 'statute_citation', 'New residents and Voters', 'batch_2026-05-13T01-40-06_wisconsin_full_v1')
INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('037af18901e4b663', 'WI', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'What is the deadline to cure a provisional ballot in Wisconsin?', '["When do I have to show my ID for my provisional ballot?","Provisional ballot curing window WI","Wisconsin absentee ballot cure deadline"]', 'If a voter casts a provisional ballot (such as lacking an acceptable photo ID), they must provide the required documentation to their municipal clerk''s office by 4:00 p.m. on the Friday following the election for the ballot to be counted.', 'https://docs.legis.wisconsin.gov/statutes/statutes/6/iv/97/3/b', 'Wis. Stat. § 6.97(3)(b)', '2026-05-12', 'static', 'statute_citation', 'Voters and Poll Watchers', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('25f6470c46d650eb', 'WI', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Does Wisconsin law require employers to give time off to vote?', '["Do I get paid time off to vote in WI?","Employee voting leave Wisconsin","3 hours off to vote rule"]', 'Yes. Under Wis. Stat. § 6.76, employers must grant employees up to three consecutive hours of unpaid leave to vote while the polls are open, provided the employee requests the time off before Election Day.', 'https://docs.legis.wisconsin.gov/statutes/statutes/6/iv/76', 'Wis. Stat. § 6.76', '2026-05-12', 'static', 'statute_citation', 'Voters and Employers', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('929d54c9a2b0d505', 'WI', '["federal","state","county","municipal","judicial"]', 'finance_ethics', 'What is the limit for anonymous campaign contributions in Wisconsin?', '["Can I donate cash anonymously in WI?","Anonymous contribution cap Wisconsin","Passing the hat rules campaign finance"]', 'Anonymous campaign contributions are strictly limited to $10 or less per donor. Any anonymous contribution exceeding $10 must be donated to a charitable organization or the Common School Fund.', 'https://docs.legis.wisconsin.gov/statutes/statutes/11/ci/1108', 'Wis. Stat. § 11.1108', '2026-05-12', 'static', 'statute_citation', 'Campaign Treasurers', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('739e89565ab3fe49', 'WI', '["federal","state","county","municipal","judicial"]', 'finance_ethics', 'When must an independent expenditure committee register in Wisconsin?', '["Super PAC registration threshold WI","Independent expenditure limits Wisconsin","When do I have to file as an IE committee?"]', 'An independent expenditure committee must register with the Wisconsin Ethics Commission before making disbursements or incurring obligations that aggregate to more than $2,500 in a calendar year.', 'https://docs.legis.wisconsin.gov/statutes/statutes/11/cv/0502', 'Wis. Stat. § 11.0502', '2026-05-12', 'static', 'statute_citation', 'Super PACs and Independent Expenditure Committees', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('19abc207346817e7', 'WI', '["federal","state","county","municipal","judicial"]', 'finance_ethics', 'What is a campaign finance conduit in Wisconsin?', '["Conduit reporting mechanism WI","How do PAC pass-throughs work in Wisconsin?","Bundling contributions legally"]', 'A conduit is a unique registration type in Wisconsin that receives contributions from individuals and passes them through to candidates. The contribution is attributed directly to the original individual donor, not the conduit, allowing donors to bundle funds without triggering PAC limits.', 'https://docs.legis.wisconsin.gov/statutes/statutes/11/cvii/0701', 'Wis. Stat. § 11.0701', '2026-05-12', 'static', 'statute_citation', 'Campaign Treasurers and Donors', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('1c4b08669d930b1b', 'WI', '["federal","state","county","municipal","judicial"]', 'finance_ethics', 'What are the standard campaign finance reporting periods in Wisconsin?', '["When are campaign finance reports due in WI?","Continuing reports schedule Wisconsin","Wisconsin campaign filing dates"]', 'Registered committees must file Continuing Reports twice a year, on January 15 and July 15. In an election year, candidates on the ballot must additionally file a Pre-Primary Report, a Pre-Election Report, and potentially a Post-Election Report.', 'https://docs.legis.wisconsin.gov/statutes/statutes/11/cii/0204', 'Wis. Stat. § 11.0204', '2026-05-12', 'static', 'statute_citation', 'Campaign Treasurers', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('46785f2a7b9258ca', 'WI', '["federal"]', 'election_dates', 'How are vacancies in the U.S. Senate filled in Wisconsin?', '["Who replaces a US Senator from Wisconsin?","Does the Governor appoint Senate vacancies in WI?","Special election for US Senate"]', 'If a U.S. Senate seat becomes vacant, the Governor appoints a replacement to serve temporarily. A special election is then scheduled to fill the remainder of the unexpired term.', 'https://docs.legis.wisconsin.gov/statutes/statutes/17/18/2', 'Wis. Stat. § 17.18(2)', '2026-05-12', 'static', 'statute_citation', 'Federal candidates', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('b917f80592d2f76c', 'WI', '["federal"]', 'election_dates', 'How are vacancies in the U.S. House of Representatives filled in Wisconsin?', '["Does the Governor appoint US House vacancies?","Special election for Congress WI","Congressional vacancy fill Wisconsin"]', 'Vacancies in the U.S. House can only be filled by a special election called by the Governor. The Governor does not have the authority to appoint an interim Representative.', 'https://docs.legis.wisconsin.gov/statutes/statutes/8/50', 'Wis. Stat. § 8.50', '2026-05-12', 'static', 'statute_citation', 'Federal candidates', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('eff11a60c88e86e1', 'WI', '["state"]', 'election_dates', 'Who succeeds the Governor of Wisconsin in the event of a vacancy?', '["What happens if the WI Governor resigns?","Lieutenant Governor succession Wisconsin","Gubernatorial vacancy fill"]', 'If the Governor dies, resigns, or is removed, the Lieutenant Governor becomes the Governor for the remainder of the unexpired term.', 'https://docs.legis.wisconsin.gov/constitution/wi/000230/000007', 'Wisconsin Constitution Article V § 7', '2026-05-12', 'static', 'statute_citation', 'Statewide officials', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('8a9c81af350614c3', 'WI', '["state"]', 'election_dates', 'How are vacancies filled for Wisconsin''s Attorney General, Secretary of State, or Treasurer?', '["Does the Governor appoint the AG?","Vacancy fill for statewide executive offices WI","Who replaces the State Treasurer?"]', 'If a vacancy occurs in a statewide executive office other than Governor or Lieutenant Governor, the Governor appoints a replacement to serve out the remainder of the unexpired term.', 'https://docs.legis.wisconsin.gov/statutes/statutes/17/19', 'Wis. Stat. § 17.19', '2026-05-12', 'static', 'statute_citation', 'Statewide officials', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('1bce241ada44d3bf', 'WI', '["state"]', 'election_dates', 'How are vacancies in the Wisconsin State Legislature filled?', '["Special election for State Assembly WI","Does the Governor appoint state senators?","Legislative vacancy fill Wisconsin"]', 'Legislative vacancies are filled exclusively by special elections called by the Governor. Unlike some states, Wisconsin does not allow the Governor or party committees to appoint interim legislators.', 'https://docs.legis.wisconsin.gov/statutes/statutes/8/50', 'Wis. Stat. § 8.50', '2026-05-12', 'static', 'statute_citation', 'State Legislative candidates', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('c0bfe4fa9afc44f6', 'WI', '["county"]', 'election_dates', 'When are county sheriffs and district attorneys elected in Wisconsin?', '["Are sheriff races partisan in WI?","District Attorney election schedule","County constitutional officer terms"]', 'Sheriffs, District Attorneys, and other county-level constitutional officers are elected in partisan elections to serve four-year terms.', 'https://docs.legis.wisconsin.gov/constitution/wi/000231/000004', 'Wisconsin Constitution Article VI § 4', '2026-05-12', 'static', 'statute_citation', 'County-level candidates', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('1c43a38f4624b236', 'WI', '["state"]', 'election_dates', 'Is the Wisconsin Superintendent of Public Instruction a partisan office?', '["When is the election for Superintendent in WI?","Nonpartisan statewide elections Wisconsin","Is the head of schools elected?"]', 'No. The Superintendent of Public Instruction is a statewide, nonpartisan office elected during the spring election to serve a four-year term, entirely separated from the fall partisan cycle.', 'https://docs.legis.wisconsin.gov/constitution/wi/000235/000001', 'Wisconsin Constitution Article X § 1', '2026-05-12', 'static', 'statute_citation', 'Statewide candidates', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('2e4df17d574476d5', 'WI', '["federal","state","county","municipal","judicial"]', 'finance_ethics', 'When must a recall committee register in Wisconsin?', '["Recall committee registration WI","Can I raise money for a recall before registering?","Wisconsin recall finance rules"]', 'A recall committee must formally register with the Wisconsin Ethics Commission and file a registration statement before it begins circulating any recall petitions against an elected official.', 'https://docs.legis.wisconsin.gov/statutes/statutes/11/cvi/0602', 'Wis. Stat. § 11.0602', '2026-05-12', 'static', 'statute_citation', 'Recall proponents', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('efbccbc91b8d3c6c', 'WI', '["state"]', 'ballot_access', 'How does the Wisconsin legislature pass a constitutional amendment?', '["Constitutional amendment process WI","Can the legislature change the constitution without voters?","Voter approval for state constitution Wisconsin"]', 'A proposed constitutional amendment must be passed by a majority vote in both chambers of the legislature during two consecutive legislative sessions. It is then placed on the ballot for final approval by Wisconsin voters.', 'https://docs.legis.wisconsin.gov/constitution/wi/000237/000001', 'Wisconsin Constitution Article XII § 1', '2026-05-12', 'static', 'statute_citation', 'Legislators and Campaigns', 'batch_2026-05-13T01-40-06_wisconsin_full_v1'),
  ('c2d7ceefcee2fa4e', 'WI', '["federal","state","county","municipal","judicial"]', 'election_dates', 'When can special elections be scheduled in Wisconsin?', '["Special election timing WI","Can a special election happen any Tuesday?","Wisconsin election calendar"]', 'Special elections in Wisconsin are generally restricted to standard election dates. They must be held concurrently with the spring primary, spring election, partisan primary, or general election, unless explicitly authorized for another date.', 'https://docs.legis.wisconsin.gov/statutes/statutes/8/50', 'Wis. Stat. § 8.50', '2026-05-12', 'static', 'statute_citation', 'Candidates and Local Officials', 'batch_2026-05-13T01-40-06_wisconsin_full_v1')
